import numpy as np
from numpy.typing import NDArray
import argparse

# Define constants for the visual symbols.
FILLED_SYMBOL = '■'
EMPTY_SYMBOL = ' '

def binary_to_ascii(row: NDArray[np.uint64], bit_width: int = 64) -> str:
    if row.size == 0:
        return ""  # Handle edge case where input is empty.

    # Convert each 64-bit integer into ASCII symbols.
    ascii_row = ''.join(
        FILLED_SYMBOL if (int(value) >> bit) & 1 else EMPTY_SYMBOL
        for value in row
        for bit in range(bit_width - 1, -1, -1)  # Iterate from MSB to LSB
    )
    return ascii_row

def print_ascii_row(row: NDArray[np.uint64], start_uint: int, end_uint: int , bit_width: int = 64):
    print(binary_to_ascii(row[start_uint: end_uint], bit_width))

# Example usage
if __name__ == "__main__":
    parser = argparse.ArgumentParser(description="Visualize a row of np.uint64 integers as ASCII symbols.")
    parser.add_argument("list", type=list, help="Comma-separated list of np.uint64 integers.")
    parser.add_argument("start", type=int, help="Start index of the row to visualize.")
    parser.add_argument("end", type=int, help="End index of the row to visualize.")
    args = parser.parse_args()
    row = np.array(args.list, dtype=np.uint64)
    print_ascii_row(row, args.start, args.end)

